  ('heelevel3-7fec267e-moex-00247', 'heelevel3-7fec267e', 'heelevel3-7fec267e-moex-111-3082b5f1', 'sub-heelevel3-7fec267e-04', NULL, 'single_choice', '關於公務人員之權利救濟，下列敘述何者正確？', '["辭職若遭拒絕，因屬機關內部之管理措施，公務人員若不服該決定，應向原服務機關提起申訴", "於復審程序或再申訴程序中，公務人員保障暨培訓委員會得依職權或依申請，進行調處", "公務人員提起申訴、再申訴，應向公務人員保障暨培訓委員會為之", "公務人員不服復審之決定，得申請再審議，若對再審議之決定仍不服，得續提行政訴訟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:38+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般行政"}'::jsonb, NULL),
  ('heelevel3-7fec267e-moex-00248', 'heelevel3-7fec267e', 'heelevel3-7fec267e-moex-111-3082b5f1', 'sub-heelevel3-7fec267e-04', NULL, 'single_choice', '依實務見解，關於公務人員之考績制度，下列敘述何者正確？', '["甲長官對於下屬收賄罪證確鑿，僅得依公務員懲戒程序處理", "乙公務員表現優異，年終考績獲甲等，應晉本俸一級，並給與1個月俸給總額之一次獎金", "丙機關就所屬公務員之考績案，送銓敘部審定時，若銓敘部發覺有違考績法情事時，銓敘部得 自行更定", "丁公務員平日辦公常遲到早退，遲誤公務，應以專案考績，列為丁等"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:38+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般行政"}'::jsonb, NULL),
  ('heelevel3-7fec267e-moex-00249', 'heelevel3-7fec267e', 'heelevel3-7fec267e-moex-111-3082b5f1', 'sub-heelevel3-7fec267e-04', NULL, 'single_choice', '關於行政規則之敘述，下列何者錯誤？', '["有效下達之行政規則，具有拘束訂定機關、其下級機關及屬官之效力", "法律授權主管機關依一定程序訂定法規命令以補充法律規定不足者，必要時，該機關亦可發布 規範行政體系內部事項之行政規則為之替代", "行政機關訂定解釋性規定及裁量基準時，應由其首長簽署，並登載於政府公報發布之", "中央主管機關為協助下級機關統一解釋法令及認定事實而就委辦事項所訂頒之解釋性規定，亦 拘束地方政府 31350、31450 32050、32750 32850 33550"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:38+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般行政"}'::jsonb, NULL),
  ('heelevel3-7fec267e-moex-00250', 'heelevel3-7fec267e', 'heelevel3-7fec267e-moex-111-3082b5f1', 'sub-heelevel3-7fec267e-04', NULL, 'single_choice', '關於授權命令之敘述，下列何者錯誤？', '["法律得授權以命令限制人民自由權利，惟其授權之目的、範圍及內容應具體明確", "行政機關訂定授權命令時，得依職權舉行聽證", "授權命令之制定須符合比例原則", "法律授權制定命令，不得以概括授權方式為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:38+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "一般行政"}'::jsonb, NULL),
